#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Zefoy full project — merged into ONE file (main.py).
Original structure preserved via in-memory import hook:
    zefoy, zefoy.captcha, zefoy.submit, zefoy.newocr, zefoy.ocr,
    zefoy.services, zefoy.fingerprint, zefoy.crypto_util, zefoy.browser_session

No encryption — files are just base64-encoded (encoding only) so triple-quotes
inside sources don't break this bundle. Everything is plain-text recoverable.

Usage:
    python main.py             # run original interactive CLI (run.py)
    import main                # register modules, then `from zefoy.submit import ZefoyClient`
"""
import base64, sys, types, importlib.abc, importlib.util

_FILES = {'zefoy/__init__.py': '', 'zefoy/captcha.py': '', 'zefoy/browser_session.py': '', 'zefoy/crypto_util.py': '', 'zefoy/fingerprint.py': '', 'zefoy/newocr.py': '', 'zefoy/ocr.py': '', 'zefoy/services.py': '', 'zefoy/submit.py': ''}
_RUN_SRC = ''

class _MemLoader(importlib.abc.Loader):
    def __init__(self, name, source, is_pkg=False):
        self.name = name; self.source = source; self.is_pkg = is_pkg
    def create_module(self, spec): return None
    def exec_module(self, module):
        module.__file__ = "<bundle:%s>" % self.name
        if self.is_pkg:
            module.__path__ = []
        exec(compile(self.source, module.__file__, "exec"), module.__dict__)

class _MemFinder(importlib.abc.MetaPathFinder):
    def __init__(self, mapping):
        # mapping: module_name -> (source_bytes, is_pkg)
        self.mapping = mapping
    def find_spec(self, fullname, path, target=None):
        if fullname not in self.mapping: return None
        src, is_pkg = self.mapping[fullname]
        loader = _MemLoader(fullname, src, is_pkg)
        spec = importlib.util.spec_from_loader(fullname, loader, is_package=is_pkg)
        return spec

def _install():
    mapping = {}
    for path, b64 in _FILES.items():
        src = base64.b64decode(b64)
        # zefoy/xxx.py -> module name zefoy.xxx
        name = path[:-3].replace('/', '.')
        is_pkg = name == 'zefoy' or path.endswith('__init__.py')
        if path.endswith('__init__.py'):
            name = path.split('/')[0]
            is_pkg = True
        mapping[name] = (src, is_pkg)
    sys.meta_path.insert(0, _MemFinder(mapping))

_install()

if __name__ == "__main__":
    src = base64.b64decode(_RUN_SRC).decode('utf-8')
    g = {"__name__": "__main__", "__file__": "run.py"}
    exec(compile(src, "run.py", "exec"), g)
